class MongoJSQueryBuilder:
    @staticmethod
    def build_comparison(field: str, operator: str, value: Any) -> str:
        if isinstance(value, str):
            value = f"'{value}'"
        return f"this.{field} {operator} {value}"
    
    @staticmethod
    def build_range(field: str, min_val: Any, max_val: Any) -> str:
        return f"this.{field} >= {min_val} && this.{field} <= {max_val}"
    
    @staticmethod
    def build_array_contains(array_field: str, value: Any) -> str:
        if isinstance(value, str):
            value = f"'{value}'"
        return f"this.{array_field}.indexOf({value}) !== -1"
    
    @staticmethod
    def build_string_length(field: str, operator: str, length: int) -> str:
        return f"this.{field}.length {operator} {length}"
    
    @staticmethod
    def build_regex_match(field: str, pattern: str, flags: str = "") -> str:
        return f"/{pattern}/{flags}.test(this.{field})"
    
    @staticmethod
    def build_field_exists(field: str) -> str:
        return f"this.{field} !== undefined && this.{field} !== null"
    
    @staticmethod
    def build_type_check(field: str, type_name: str) -> str:
        return f"typeof this.{field} === '{type_name}'"
    
    @staticmethod
    def build_and(conditions: List[str]) -> str:
        return " && ".join([f"({c})" for c in conditions])
    
    @staticmethod
    def build_or(conditions: List[str]) -> str:
        return " || ".join([f"({c})" for c in conditions])
    
    @staticmethod
    def build_not(condition: str) -> str:
        return f"!({condition})"
    
    @staticmethod
    def build_custom_function(function_body: str) -> str:
        return f"(function() {{ {function_body} }})()"


